import { useState, useEffect } from 'react';
import './App.css'; // يمكنك استخدام تنسيقات CSS الخاصة بك هنا

// 🚀 ضع الـ ALB DNS الخاص بك هنا
const ALB_BASE_URL = "http://YOUR-ALB-DNS-NAME.region.elb.amazonaws.com";

function App() {
  const [products, setProducts] = useState([]);
  const [bestsellers, setBestsellers] = useState([]);
  const [cart, setCart] = useState([]);
  const [authToken, setAuthToken] = useState(null);
  const [showCart, setShowCart] = useState(false);

  // جلب البيانات عند تحميل المكون
  useEffect(() => {
    fetchProducts();
    fetchBestSellers();
  }, []);

  // نداء Fargate & MongoDB
  const fetchProducts = async () => {
    try {
      const response = await fetch(`${ALB_BASE_URL}/products`);
      if (response.ok) {
        setProducts(await response.json());
      } else {
        throw new Error("Backend not ready");
      }
    } catch (error) {
      // داتا وهمية للمحاكاة حتى تشغل الـ Backend
      setProducts([
        { id: 1, name: "لابتوب للمطورين", price: 1200 },
        { id: 2, name: "شاشة 27 بوصة", price: 300 },
        { id: 3, name: "لوحة مفاتيح ميكانيكية", price: 80 }
      ]);
    }
  };

  // نداء Lambda
  const fetchBestSellers = async () => {
    try {
      const response = await fetch(`${ALB_BASE_URL}/bestsellers`);
      if (response.ok) {
        setBestsellers(await response.json());
      } else {
        throw new Error("Backend not ready");
      }
    } catch (error) {
      setBestsellers([
        { id: 4, name: "سماعة عزل ضوضاء", price: 150 },
        { id: 5, name: "ماوس وايرلس", price: 40 }
      ]);
    }
  };

  // محاكاة تسجيل الدخول مع Cognito
  const loginWithCognito = () => {
    alert("سيتم توجيهك إلى Hosted UI الخاصة بـ Cognito...");
    setAuthToken("dummy-jwt-token-from-cognito");
  };

  // وظائف السلة
  const addToCart = (product) => setCart([...cart, product]);
  const removeFromCart = (index) => {
    const newCart = [...cart];
    newCart.splice(index, 1);
    setCart(newCart);
  };
  const cartTotal = cart.reduce((sum, item) => sum + item.price, 0);

  // نداء EC2 & SQS
  const checkout = async () => {
    if (cart.length === 0) return alert("السلة فارغة!");
    if (!authToken) return alert("يرجى تسجيل الدخول عبر Cognito أولاً!");

    const orderPayload = { items: cart, total: cartTotal };

    try {
      const response = await fetch(`${ALB_BASE_URL}/checkout`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${authToken}`
        },
        body: JSON.stringify(orderPayload)
      });

      alert("✅ تم الإرسال للـ ALB، ومنه للـ EC2، ثم لـ SQS!");
      setCart([]);
      setShowCart(false);
    } catch (error) {
      console.log("Payload:", orderPayload);
      alert("✅ (محاكاة) تم وضع الطلب في طابور SQS بنجاح.");
      setCart([]);
      setShowCart(false);
    }
  };

  return (
    <div style={{ fontFamily: 'Tahoma, sans-serif', direction: 'rtl', padding: '20px' }}>
      {/* Header */}
      <header style={{ display: 'flex', justifyContent: 'space-between', background: '#232f3e', color: 'white', padding: '15px' }}>
        <h2>متجري السحابي ☁️</h2>
        <div>
          <span style={{ marginRight: '15px' }}>
            {authToken ? "✅ مسجل الدخول" : "❌ غير مسجل الدخول"}
          </span>
          {!authToken && <button onClick={loginWithCognito} style={{ marginRight: '10px' }}>تسجيل الدخول</button>}
          <button onClick={() => setShowCart(!showCart)}>🛒 السلة ({cart.length})</button>
        </div>
      </header>

      {/* Cart Section */}
      {showCart && (
        <div style={{ background: '#f9f9f9', padding: '20px', borderBottom: '2px solid #ccc' }}>
          <h3>سلة المشتريات</h3>
          {cart.map((item, idx) => (
            <div key={idx} style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px' }}>
              <span>{item.name}</span>
              <span>${item.price} <button onClick={() => removeFromCart(idx)}>❌</button></span>
            </div>
          ))}
          <h4>الإجمالي: ${cartTotal}</h4>
          <button onClick={checkout} style={{ background: '#f0c14b', padding: '10px', width: '100%' }}>
            إتمام الدفع (إرسال إلى SQS)
          </button>
        </div>
      )}

      {/* Best Sellers (Lambda) */}
      <h3>🔥 الأكثر مبيعاً (من Lambda)</h3>
      <div style={{ display: 'flex', gap: '20px' }}>
        {bestsellers.map(p => (
          <div key={p.id} style={{ border: '1px solid #ddd', padding: '15px', borderRadius: '5px' }}>
            <h4>{p.name}</h4>
            <p>${p.price}</p>
            <button onClick={() => addToCart(p)}>أضف للسلة</button>
          </div>
        ))}
      </div>

      <hr style={{ margin: '30px 0' }} />

      {/* All Products (Fargate + MongoDB) */}
      <h3>📦 كل المنتجات (من Fargate & MongoDB)</h3>
      <div style={{ display: 'flex', gap: '20px', flexWrap: 'wrap' }}>
        {products.map(p => (
          <div key={p.id} style={{ border: '1px solid #ddd', padding: '15px', borderRadius: '5px' }}>
            <h4>{p.name}</h4>
            <p>${p.price}</p>
            <button onClick={() => addToCart(p)}>أضف للسلة</button>
          </div>
        ))}
      </div>
    </div>
  );
}

export default App;
